{
  "grammar": [
    {
      "pattern": "因為 + reason，所以 + result",
      "structure": ["因為", "reason", "，", "所以", "result"],
      "explanation_en": "Use '因為...所以...' to express cause and effect. The reason comes after '因為' and the result comes after '所以'. This structure is commonly used in both spoken and written Chinese.",
      "title": "因為...所以... (Cause and Effect)",
      "meaning": "Because... therefore...",
      "when_to_use": ["When explaining why you want or don't want something", "When giving a reason for an action or decision", "In both formal and informal conversations"],
      "when_not_to_use": ["When the reason is obvious from context (can omit 因為)", "In very casual speech where 所以 alone might suffice"],
      "pragmatic_notes": "In Taiwan, this structure is very common in daily conversations. You can also use just '所以' without '因為' if the reason is clear. For example, '我累了，所以想休息' is natural.",
      "word_order_notes": "The reason clause always comes first, followed by the result clause. This is the opposite of English where 'because' can come at the end.",
      "english_contrast": "In English, you can say 'I want to rest because I'm tired' or 'Because I'm tired, I want to rest.' In Chinese, the reason must come first: '因為我累了，所以想休息.'",
      "korean_contrast": "In Korean, '~기 때문에' or '~아서/어서' is used for cause and effect, similar to Chinese. However, Korean often omits the result clause if it's implied, while Chinese usually includes it.",
      "negative_examples": [
        {
          "text": "所以我想休息因為我累了。",
          "error": "The reason must come before the result. Use '因為...所以...' structure."
        },
        {
          "text": "因為我累了，我想休息。",
          "error": "Missing '所以' before the result. In Chinese, '所以' is often needed to connect cause and effect clearly."
        }
      ],
      "incorrect_examples": [
        {
          "text": "因為我沒睡飽，所以我今天很累。",
          "error": "This sentence is actually correct. No error here."
        },
        {
          "text": "因為我肚子餓，所以我想吃東西。",
          "error": "This is correct. No error."
        }
      ],
      "transformation_drills": ["Change '我累了，所以想休息' to use '因為'", "Change '因為下雨了，所以不去公園' to omit '因為'"],
      "production_drills": ["Explain why you want to eat now using 因為...所以...", "Explain why you don't want to go out today"],
      "common_error_patterns": ["Placing the result before the reason", "Omitting 所以 when the reason is stated"],
      "repair_feedback": {
        "word_order": "Remember: reason first, then result. Use 因為 for reason, 所以 for result.",
        "politeness": "This structure is neutral and can be used in any context.",
        "vocabulary": "Use appropriate reason words like 肚子餓, 口渴, 生病, 感冒, 頭痛, 沒睡飽, 太累了, 太忙了, 下雨了, 塞車了."
      }
    },
    {
      "pattern": "為什麼 + question?",
      "structure": ["為什麼", "question"],
      "explanation_en": "Use '為什麼' to ask 'why' questions. It is placed at the beginning of the sentence to inquire about the reason for an action or situation.",
      "title": "為什麼 (Why)",
      "meaning": "Why",
      "when_to_use": ["When asking for a reason or explanation", "In both formal and informal contexts", "When you want to understand someone's motivation"],
      "when_not_to_use": ["When asking about the method (use 怎麼 instead)", "When the reason is already known"],
      "pragmatic_notes": "In Taiwan, '為什麼' is very common. In casual speech, you might also hear '幹嘛' but it's less polite. '為什麼' is safe in most situations.",
      "word_order_notes": "為什麼 comes at the beginning of the question, followed by the subject and verb. For example: '為什麼你不想吃？'",
      "english_contrast": "In English, 'why' can come at the beginning or end ('Why are you tired?' or 'You are tired why?'). In Chinese, '為什麼' must come at the beginning.",
      "korean_contrast": "In Korean, '왜' is used similarly at the beginning of questions, e.g., '왜 피곤해요?' (Why are you tired?).",
      "negative_examples": [
        {
          "text": "你為什麼不想吃？",
          "error": "This is correct. No error."
        },
        {
          "text": "為什麼你不想吃？",
          "error": "This is also correct. Both word orders are acceptable."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你不想吃為什麼？",
          "error": "為什麼 must come at the beginning of the question, not the end."
        },
        {
          "text": "為什麼你？",
          "error": "Incomplete sentence. You need to include the verb and object."
        }
      ],
      "transformation_drills": ["Change '你為什麼不想去？' to a statement using 因為...所以...", "Ask 'why' for the reason '因為我累了'"],
      "production_drills": ["Ask a friend why they are late", "Ask why someone doesn't want to eat"],
      "common_error_patterns": ["Placing 為什麼 at the end of the sentence", "Omitting the verb after 為什麼"],
      "repair_feedback": {
        "word_order": "Put 為什麼 at the beginning of the question.",
        "politeness": "Using 為什麼 is polite. For very formal situations, you can say '請問為什麼'.",
        "vocabulary": "Use with verbs like 想, 要, 喜歡, 需要, 可以."
      }
    },
    {
      "pattern": "所以 + result (without 因為)",
      "structure": ["所以", "result"],
      "explanation_en": "Use '所以' alone to indicate a result when the reason is already understood from context. This is common in casual conversation.",
      "title": "所以 (Therefore - without 因為)",
      "meaning": "Therefore / So",
      "when_to_use": ["When the reason is obvious from the previous conversation", "In casual speech to express a conclusion", "When you want to be concise"],
      "when_not_to_use": ["When the reason is not clear and needs to be stated", "In formal writing where full structure is preferred"],
      "pragmatic_notes": "In Taiwan, using '所以' alone is very common in daily speech. For example, after someone says '我累了', you can respond '所以你想休息嗎？'",
      "word_order_notes": "所以 comes at the beginning of the result clause. The subject can come after 所以 or be omitted if clear.",
      "english_contrast": "In English, 'so' can be used similarly: 'I'm tired, so I want to rest.' In Chinese, '所以' functions the same way.",
      "korean_contrast": "In Korean, '그래서' is used similarly to '所以' to indicate result without restating the reason.",
      "negative_examples": [
        {
          "text": "所以我想休息。",
          "error": "This is correct if the reason is already known. No error."
        },
        {
          "text": "所以因為我累了想休息。",
          "error": "Do not use 因為 and 所以 together in the same clause. Use either full structure or just 所以."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我累了所以想休息。",
          "error": "This is actually correct in casual speech. No error."
        },
        {
          "text": "所以因為我沒睡飽。",
          "error": "所以 should introduce the result, not the reason. Use 因為 for the reason."
        }
      ],
      "transformation_drills": ["Change '因為我肚子餓，所以想吃飯' to use only 所以", "Respond to '我太忙了' using 所以"],
      "production_drills": ["Explain why you are late using only 所以 after stating the reason", "Ask a question using 所以 to confirm a result"],
      "common_error_patterns": ["Using 所以 with 因為 in the same sentence incorrectly", "Using 所以 when the reason is not clear"],
      "repair_feedback": {
        "word_order": "所以 comes before the result. If the reason is stated, put it first.",
        "politeness": "Using 所以 alone is casual. In formal contexts, use full 因為...所以...",
        "vocabulary": "Use result verbs like 想, 要, 需要, 可以, 打算."
      }
    }
  ]
}
